/* global Office */

import "./ribbonActions";

function setStatus(message: string): void {
  const target = document.getElementById("status-text");
  if (target) target.textContent = message;
}

Office.onReady((info) => {
  if (info.host !== Office.HostType.Excel) return;
  const sideloadMessage = document.getElementById("sideload-msg");
  const appBody = document.getElementById("app-body");
  if (sideloadMessage) sideloadMessage.style.display = "none";
  if (appBody) appBody.style.display = "block";
  setStatus("TraceForge ribbon is ready. Use the TraceForge tab.");
});
