import {
  astToNodeRows,
  collectEvaluableNodes,
  formatDisplayValue,
  qualifyAstToFormula,
} from "../core/astToNodeRows";
import type { AstNode, NodeRow } from "../core/astTypes";
import { FormulaParseError, parseFormula } from "../core/formulaParser";
import type { FormulaExplorerPort } from "../adapters/formulaExplorerPort";

export type FormulaExplorerModel = {
  rootAddress: string;
  rawFormula: string;
  nodes: NodeRow[];
  parseError?: string;
};

export async function buildFormulaExplorerModel(
  port: FormulaExplorerPort
): Promise<FormulaExplorerModel | null> {
  const root = await port.getActiveFormulaCell();
  if (!root) return null;

  let ast: AstNode;
  let parseError: string | undefined;
  try {
    ast = parseFormula(root.formula);
  } catch (error) {
    parseError =
      error instanceof FormulaParseError || error instanceof Error
        ? error.message
        : "Could not parse formula.";
    ast = { kind: "root", child: { kind: "unknown", text: root.formula, start: 0, end: root.formula.length }, start: 0, end: root.formula.length };
  }

  const evaluable = parseError
    ? []
    : collectEvaluableNodes(ast).map(({ id, node }) => ({
        id,
        formula: `=${qualifyAstToFormula(node, root.sheetName)}`,
      }));

  let evaluated: Record<string, unknown> = {};
  if (evaluable.length > 0) {
    try {
      evaluated = await port.evaluateFormulaExpressions(root.sheetName, evaluable, root.numberFormat);
    } catch {
      evaluated = Object.fromEntries(evaluable.map((item) => [item.id, "<eval unavailable>"]));
    }
  }

  const valueMap = Object.fromEntries(
    Object.entries(evaluated).map(([id, value]) => [
      id,
      typeof value === "string" ? value : formatDisplayValue(value),
    ])
  );
  const nodes = astToNodeRows({
    ast,
    formula: root.formula,
    sourceSheet: root.sheetName,
    sourceAddress: root.address,
    sourceLabel: root.label,
    rootValue: parseError ? "<parse error>" : root.displayValue ?? formatDisplayValue(root.value),
    values: valueMap,
  });

  return {
    rootAddress: `${root.sheetName}!${root.address}`,
    rawFormula: root.formula,
    nodes,
    parseError,
  };
}
