/* global Excel, Office */

import {
  buildDataFlowModel,
  type DataFlowEdge,
  type DataFlowModel,
  type DataFlowSheetSnapshot,
} from "../core/dataFlow";

let activeDialog: Office.Dialog | null = null;
let activeSessionId = 0;
let pendingModel: DataFlowModel | null = null;
let dialogReady = false;

const MAX_SELECT_CELLS = 100;

type DialogMessage =
  | { action: "ready" }
  | { action: "selectFlowLink"; fromSheet: string; toSheet: string }
  | { action: "exportDataFlow" }
  | { action: "close" };

export async function openDataFlowDialog(): Promise<void> {
  await closeDataFlowDialog();
  dialogReady = false;
  pendingModel = null;
  activeSessionId += 1;
  const sessionId = activeSessionId;
  const url = new URL("dataFlowDialog.html", window.location.href);
  Office.context.ui.displayDialogAsync(
    url.toString(),
    { height: 65, width: 75, displayInIframe: true },
    (result) => {
      if (result.status !== Office.AsyncResultStatus.Succeeded) return;
      const dialog = result.value;
      activeDialog = dialog;
      dialog.addEventHandler(Office.EventType.DialogMessageReceived, (arg) =>
        handleDialogMessage(dialog, sessionId, arg)
      );
      dialog.addEventHandler(Office.EventType.DialogEventReceived, () => {
        if (activeDialog === dialog) void closeDataFlowDialog();
      });
      void loadAndSendDataFlowModel(dialog, sessionId);
    }
  );
}

async function loadAndSendDataFlowModel(dialog: Office.Dialog, sessionId: number): Promise<void> {
  try {
    const model = await readDataFlowModel();
    if (activeDialog !== dialog || sessionId !== activeSessionId) return;
    pendingModel = model;
    if (dialogReady) dialog.messageChild(JSON.stringify({ action: "setDataFlow", model }));
  } catch {
    if (activeDialog === dialog && sessionId === activeSessionId && dialogReady) {
      dialog.messageChild(JSON.stringify({ action: "error", message: "Could not build Data Flow." }));
    }
  }
}

async function closeDataFlowDialog(): Promise<void> {
  if (activeDialog) {
    try {
      activeDialog.close();
    } catch {
      // Already closed.
    }
    activeDialog = null;
  }
  pendingModel = null;
  dialogReady = false;
  schedulePullFocusToGrid();
}

async function readDataFlowModel(): Promise<DataFlowModel> {
  let snapshots: DataFlowSheetSnapshot[] = [];
  await Excel.run(async (context) => {
    const sheets = context.workbook.worksheets;
    sheets.load("items/name,items/visibility");
    await context.sync();

    const queued = sheets.items.map((sheet) => {
      const used = sheet.getUsedRangeOrNullObject(true);
      used.load(["isNullObject", "rowIndex", "columnIndex", "formulas"]);
      return { sheet, used };
    });
    await context.sync();

    snapshots = queued.map(({ sheet, used }) => ({
      name: sheet.name,
      hidden: String(sheet.visibility).toLowerCase() !== "visible",
      startRow: used.isNullObject ? 0 : used.rowIndex,
      startColumn: used.isNullObject ? 0 : used.columnIndex,
      formulas: used.isNullObject ? [] : (used.formulas as string[][]),
    }));
  });
  return buildDataFlowModel(snapshots);
}

function parseDialogMessage(raw: unknown): DialogMessage | null {
  if (typeof raw !== "string") return null;
  try {
    const parsed = JSON.parse(raw) as Partial<DialogMessage>;
    if (parsed.action === "ready") return { action: "ready" };
    if (
      parsed.action === "selectFlowLink" &&
      typeof parsed.fromSheet === "string" &&
      typeof parsed.toSheet === "string"
    ) {
      return { action: parsed.action, fromSheet: parsed.fromSheet, toSheet: parsed.toSheet };
    }
    if (parsed.action === "exportDataFlow") return { action: "exportDataFlow" };
    if (parsed.action === "close") return { action: "close" };
  } catch {
    return null;
  }
  return null;
}

function handleDialogMessage(
  dialog: Office.Dialog,
  sessionId: number,
  arg: { message?: string } | { error: number }
): void {
  if (activeDialog !== dialog || sessionId !== activeSessionId || !("message" in arg)) return;
  const msg = parseDialogMessage(arg.message);
  if (!msg) return;
  if (msg.action === "ready") {
    dialogReady = true;
    if (pendingModel) dialog.messageChild(JSON.stringify({ action: "setDataFlow", model: pendingModel }));
    return;
  }
  if (msg.action === "selectFlowLink") {
    void selectEdgeCells(dialog, sessionId, msg.fromSheet, msg.toSheet);
    return;
  }
  if (msg.action === "exportDataFlow") {
    void exportDataFlow();
    return;
  }
  if (msg.action === "close") void closeDataFlowDialog();
}

async function selectEdgeCells(
  dialog: Office.Dialog,
  sessionId: number,
  fromSheet: string,
  toSheet: string
): Promise<void> {
  const edge = findEdge(fromSheet, toSheet);
  if (!edge || edge.formulaCells.length === 0) return;
  const addresses = edge.formulaCells.slice(0, MAX_SELECT_CELLS).map((cell) => cell.address);
  let selected = addresses.length;
  try {
    await selectAddresses(edge.fromSheet, addresses);
    sendSelectionStatus(dialog, sessionId, renderSelectionStatus(edge, selected));
  } catch {
    try {
      selected = 1;
      await selectSingleAddress(edge.fromSheet, addresses[0]);
      sendSelectionStatus(dialog, sessionId, renderSelectionStatus(edge, selected));
    } catch (error) {
      sendSelectionStatus(dialog, sessionId, selectionErrorMessage(edge.fromSheet, error));
    }
  }
}

async function selectAddresses(sheetName: string, addresses: string[]): Promise<void> {
  await Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.getItemOrNullObject(sheetName);
    sheet.load(["isNullObject", "visibility"]);
    await context.sync();
    if (sheet.isNullObject || String(sheet.visibility).toLowerCase() !== "visible") {
      throw new Error("Cannot select cells on a hidden or missing sheet.");
    }
    sheet.activate();
    if (!Office.context.requirements.isSetSupported("ExcelApi", "1.18")) {
      throw new Error("Multi-range selection is not supported in this Excel host.");
    }
    sheet.getRanges(mergeAddresses(addresses).join(",")).select();
    if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) context.workbook.focus();
    await context.sync();
  });
}

async function selectSingleAddress(sheetName: string, address: string): Promise<void> {
  await Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.getItemOrNullObject(sheetName);
    sheet.load(["isNullObject", "visibility"]);
    await context.sync();
    if (sheet.isNullObject || String(sheet.visibility).toLowerCase() !== "visible") {
      throw new Error("Cannot select cells on a hidden or missing sheet.");
    }
    sheet.activate();
    sheet.getRange(address).select();
    if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) context.workbook.focus();
    await context.sync();
  });
}

async function exportDataFlow(): Promise<void> {
  const model = pendingModel;
  if (!model) return;
  await Excel.run(async (context) => {
    const sheet = context.workbook.worksheets.add(uniqueSheetName("Data Flow"));
    const matrix = makeMatrix(model);
    const range = sheet.getRangeByIndexes(0, 0, matrix.length, matrix[0]?.length ?? 1);
    range.values = matrix;
    range.format.autofitColumns();
    sheet.activate();
    await context.sync();
  });
}

function makeMatrix(model: DataFlowModel): unknown[][] {
  const edgeMap = new Map(model.edges.map((edge) => [edgeKey(edge.fromSheet, edge.toSheet), edge.count]));
  const header = ["", ...model.sheets.map(renderSheetName)];
  return [
    header,
    ...model.sheets.map((from) => [
      renderSheetName(from),
      ...model.sheets.map((to) => edgeMap.get(edgeKey(from.name, to.name)) ?? ""),
    ]),
  ];
}

function findEdge(fromSheet: string, toSheet: string): DataFlowEdge | undefined {
  return pendingModel?.edges.find((edge) => edge.fromSheet === fromSheet && edge.toSheet === toSheet);
}

function edgeKey(fromSheet: string, toSheet: string): string {
  return `${fromSheet}\u0000${toSheet}`;
}

function renderSheetName(sheet: { name: string; hidden: boolean }): string {
  return sheet.hidden ? `${sheet.name} (hidden)` : sheet.name;
}

function schedulePullFocusToGrid(): void {
  setTimeout(() => {
    if (activeDialog !== null) return;
    void Excel.run(async (context) => {
      if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
        context.workbook.focus();
        await context.sync();
      }
    });
  }, 50);
}

function uniqueSheetName(base: string): string {
  const stamp = new Date().toISOString().slice(11, 23).replace(/[:.]/g, "");
  return `${base} ${stamp}`.replace(/[\\/?*:[\]]/g, " ").slice(0, 31).trim();
}

function renderSelectionStatus(edge: DataFlowEdge, selected: number): string {
  if (selected === 1 && edge.formulaCells.length > 1) {
    return `Selected first cell only of ${edge.formulaCells.length} formula cells: ${edge.fromSheet} -> ${edge.toSheet}`;
  }
  if (selected < edge.formulaCells.length) {
    return `Selected first ${selected} of ${edge.formulaCells.length} formula cells: ${edge.fromSheet} -> ${edge.toSheet}`;
  }
  return `Selected ${selected} formula cells: ${edge.fromSheet} -> ${edge.toSheet}`;
}

function sendSelectionStatus(dialog: Office.Dialog, sessionId: number, message: string): void {
  if (activeDialog !== dialog || sessionId !== activeSessionId || !dialogReady) return;
  dialog.messageChild(JSON.stringify({ action: "selectionStatus", message }));
}

function selectionErrorMessage(sheetName: string, error: unknown): string {
  const message = error instanceof Error ? error.message : "";
  if (message.includes("hidden or missing")) return `Cannot select hidden source sheet: ${sheetName}`;
  return "Could not select linked formula cells.";
}

function mergeAddresses(addresses: string[]): string[] {
  const byColumn = new Map<string, number[]>();
  const fallback: string[] = [];
  for (const address of addresses) {
    const match = /^(\$?[A-Z]{1,3})\$?(\d{1,7})$/i.exec(address);
    if (!match) {
      fallback.push(address);
      continue;
    }
    const column = match[1].replace(/\$/g, "").toUpperCase();
    const row = Number(match[2]);
    const rows = byColumn.get(column) ?? [];
    rows.push(row);
    byColumn.set(column, rows);
  }

  const ranges: string[] = [...fallback];
  for (const [column, rows] of byColumn) {
    rows.sort((a, b) => a - b);
    let start = rows[0];
    let previous = rows[0];
    for (let index = 1; index <= rows.length; index += 1) {
      const row = rows[index];
      if (row === previous + 1) {
        previous = row;
        continue;
      }
      ranges.push(start === previous ? `${column}${start}` : `${column}${start}:${column}${previous}`);
      start = row;
      previous = row;
    }
  }
  return ranges;
}
