/* global Excel, Office */

import type { FormulaExplorerPort, FormulaExplorerRoot } from "../adapters/formulaExplorerPort";
import { buildFormulaExplorerModel, type FormulaExplorerModel } from "../services/formulaExplorerService";
import {
  astToNodeRows,
  computeLeftLabelLookupWindow,
  formatWorkbookDisplayValue,
  pickNearestLeftLabel,
} from "../core/astToNodeRows";
import type { NodeRow } from "../core/astTypes";
import { parseFormula } from "../core/formulaParser";

let activeDialog: Office.Dialog | null = null;
let activeSessionId = 0;
let pendingModel: FormulaExplorerModel | null = null;
let originalRootFill: SavedFill | null = null;
let rootAddress: { sheetName: string; address: string } | null = null;
let highlightedNodeFills: SavedFill[] = [];
let highlightRunId = 0;
let isExplorerClosing = false;
let highlightQueue: Promise<void> = Promise.resolve();

const ROOT_HIGHLIGHT_COLOR = "#D8BFD8";
const NODE_HIGHLIGHT_COLOR = "#10D7B0";
const MAX_DEPENDENCY_DEPTH = 15;
const MAX_EXPANDED_RANGE_CELLS = 200;
const MAX_HIGHLIGHT_CELLS = 50;
const INLINE_RANGE_CELL_LIMIT = 50;
const LABEL_LOOKUP_LEFT_COLUMNS = 15;

type SavedFill = {
  sheetName: string;
  address: string;
  color: string | null;
  pattern: string | null;
};

class LiveFormulaExplorerPort implements FormulaExplorerPort {
  async getActiveFormulaCell(): Promise<FormulaExplorerRoot | null> {
    let result: FormulaExplorerRoot | null = null;
    await Excel.run(async (context) => {
      const cell = context.workbook.getActiveCell();
      cell.load(["address", "formulas", "values", "text", "numberFormat", "rowIndex", "columnIndex", "worksheet/name"]);
      cell.format.fill.load(["color", "pattern"]);
      const usedRange = cell.worksheet.getUsedRangeOrNullObject();
      usedRange.load(["isNullObject", "columnIndex"]);
      await context.sync();

      const formula = String(cell.formulas?.[0]?.[0] ?? "");
      if (!formula.startsWith("=")) return;

      const address = String(cell.address).split("!").pop() ?? String(cell.address);
      const label = await readActiveCellLeftLabel(context, cell, usedRange);
      result = {
        sheetName: cell.worksheet.name,
        address,
        formula,
        value: cell.values?.[0]?.[0],
        displayValue: cell.text?.[0]?.[0],
        numberFormat: String(cell.numberFormat?.[0]?.[0] ?? ""),
        label,
      };
      rootAddress = { sheetName: cell.worksheet.name, address };
      originalRootFill = {
        sheetName: cell.worksheet.name,
        address,
        color: cell.format.fill.color ?? null,
        pattern: cell.format.fill.pattern ?? null,
      };
      cell.format.fill.pattern = "Solid";
      cell.format.fill.color = ROOT_HIGHLIGHT_COLOR;
      await context.sync();
    });
    return result;
  }

  async evaluateFormulaExpressions(
    _sourceSheet: string,
    formulas: Array<{ id: string; formula: string }>,
    sourceNumberFormat?: string
  ): Promise<Record<string, unknown>> {
    if (formulas.length === 0) return {};
    const values: Record<string, unknown> = {};
    await Excel.run(async (context) => {
      let helper = context.workbook.worksheets.getItemOrNullObject("__TraceForgeEval__");
      helper.load("isNullObject");
      await context.sync();
      if (helper.isNullObject) helper = context.workbook.worksheets.add("__TraceForgeEval__");
      helper.visibility = Excel.SheetVisibility.hidden;
      const range = helper.getRangeByIndexes(0, 0, formulas.length, 1);
      if (sourceNumberFormat) {
        range.numberFormat = formulas.map(() => [sourceNumberFormat]);
      }
      range.formulas = formulas.map((item) => [item.formula]);
      range.load(["values", "text"]);
      await context.sync();
      formulas.forEach((item, index) => {
        values[item.id] = formatWorkbookDisplayValue(range.text?.[index]?.[0], range.values?.[index]?.[0]);
      });
      range.clear(Excel.ClearApplyTo.contents);
      await context.sync();
    });
    return values;
  }
}

async function readActiveCellLeftLabel(
  context: Excel.RequestContext,
  cell: Excel.Range,
  usedRange: Excel.Range
): Promise<string | undefined> {
  const window = computeLeftLabelLookupWindow({
    targetColumnIndex: cell.columnIndex,
    usedStartColumnIndex: usedRange.isNullObject ? 0 : usedRange.columnIndex,
    maxColumns: LABEL_LOOKUP_LEFT_COLUMNS,
  });
  if (!window) return undefined;
  const labelRange = cell.worksheet.getRangeByIndexes(cell.rowIndex, window.startColumnIndex, 1, window.columnCount);
  labelRange.load(["text", "formulas"]);
  await context.sync();
  const text = labelRange.text?.[0] ?? [];
  const formulas = labelRange.formulas?.[0] ?? [];
  const label = pickNearestLeftLabel(
    text.map((cellText, index) => ({
      text: cellText,
      formula: formulas[index],
    }))
  );
  return label || undefined;
}

export async function openFormulaExplorerDialog(): Promise<void> {
  await closeFormulaExplorerDialog();
  isExplorerClosing = false;
  const model = await buildFormulaExplorerModel(new LiveFormulaExplorerPort());
  if (!model) {
    const status = document.getElementById("status-text");
    if (status) status.textContent = "Select a cell containing a formula.";
    // eslint-disable-next-line no-console
    console.log("Select a cell containing a formula.");
    return;
  }
  pendingModel = model;
  activeSessionId += 1;
  const sessionId = activeSessionId;
  const url = new URL("formulaExplorerDialog.html", window.location.href);
  Office.context.ui.displayDialogAsync(
    url.toString(),
    { height: 45, width: 30, displayInIframe: true },
    (result) => {
      if (result.status !== Office.AsyncResultStatus.Succeeded) {
        void restoreFormulaExplorerRoot();
        return;
      }
      const dialog = result.value;
      activeDialog = dialog;
      dialog.addEventHandler(Office.EventType.DialogMessageReceived, (arg) =>
        handleDialogMessage(dialog, sessionId, arg)
      );
      dialog.addEventHandler(Office.EventType.DialogEventReceived, () => {
        if (activeDialog === dialog) void closeFormulaExplorerDialog();
      });
    }
  );
}

export async function closeFormulaExplorerDialog(): Promise<void> {
  isExplorerClosing = true;
  highlightRunId += 1;
  if (activeDialog) {
    try {
      activeDialog.close();
    } catch {
      // Already closed.
    }
    activeDialog = null;
  }
  pendingModel = null;
  await highlightQueue.catch(() => undefined);
  await restoreHighlightedNode();
  await restoreFormulaExplorerRoot();
  schedulePullFocusToGrid();
}

type DialogMessage =
  | { action: "ready" }
  | { action: "navigate"; location: string; locations?: string[] }
  | { action: "expandReference"; row: NodeRow }
  | { action: "close" };

function parseDialogMessage(raw: unknown): DialogMessage | null {
  if (typeof raw !== "string") return null;
  try {
    const parsed = JSON.parse(raw) as Partial<DialogMessage>;
    if (parsed.action === "ready") return { action: "ready" };
    if (parsed.action === "navigate" && typeof parsed.location === "string") {
      const locations = (parsed as { locations?: unknown }).locations;
      return {
        action: "navigate",
        location: parsed.location,
        locations: Array.isArray(locations) ? locations.filter((item): item is string => typeof item === "string") : undefined,
      };
    }
    if (parsed.action === "expandReference" && typeof (parsed as { row?: unknown }).row === "object") {
      return { action: "expandReference", row: (parsed as { row: NodeRow }).row };
    }
    if (parsed.action === "close") return { action: "close" };
  } catch {
    return null;
  }
  return null;
}

function handleDialogMessage(
  dialog: Office.Dialog,
  sessionId: number,
  arg: { message?: string } | { error: number }
): void {
  if (activeDialog !== dialog || sessionId !== activeSessionId || !("message" in arg)) return;
  const msg = parseDialogMessage(arg.message);
  if (!msg) return;
  if (msg.action === "ready") {
    dialog.messageChild(JSON.stringify({ action: "setTree", ...pendingModel }));
    return;
  }
  if (msg.action === "navigate") {
    const runId = ++highlightRunId;
    const locations = msg.locations?.length ? msg.locations : [msg.location];
    highlightQueue = highlightQueue.catch(() => undefined).then(() => selectLocations(locations, runId));
    void highlightQueue;
    return;
  }
  if (msg.action === "expandReference") {
    void expandReference(dialog, msg.row);
    return;
  }
  if (msg.action === "close") void closeFormulaExplorerDialog();
}

async function selectLocations(locations: string[], runId: number): Promise<void> {
  const parsedLocations = locations.map(parseFormulaExplorerLocation).filter((item): item is ParsedLocation => item !== null);
  if (parsedLocations.length === 0) return;
  if (!isHighlightCurrent(runId)) return;
  try {
    await restoreHighlightedNode();
    if (!isHighlightCurrent(runId)) return;
    await Excel.run(async (context) => {
      const sheets = new Map<string, Excel.Worksheet>();
      for (const parsed of parsedLocations) {
        if (sheets.has(parsed.sheetName)) continue;
        const sheet = context.workbook.worksheets.getItemOrNullObject(parsed.sheetName);
        sheet.load("isNullObject");
        sheets.set(parsed.sheetName, sheet);
      }
      await context.sync();
      if (!isHighlightCurrent(runId)) return;
      const first = parsedLocations[0];
      const firstSheet = sheets.get(first.sheetName);
      if (!firstSheet || firstSheet.isNullObject) return;
      firstSheet.activate();
      firstSheet.getRange(first.address).select();
      await highlightLocations(context, sheets, parsedLocations, runId);
      if (!isHighlightCurrent(runId)) return;
      if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
        context.workbook.focus();
      }
      await context.sync();
    });
  } catch {
    // Navigation errors should not close the inspector.
  }
}

async function highlightLocations(
  context: Excel.RequestContext,
  sheets: Map<string, Excel.Worksheet>,
  parsedLocations: ParsedLocation[],
  runId: number
): Promise<void> {
  const ranges: Array<{ sheetName: string; range: Excel.Range }> = [];
  let totalCells = 0;
  for (const parsed of parsedLocations) {
    const sheet = sheets.get(parsed.sheetName);
    if (!sheet || sheet.isNullObject) continue;
    const range = sheet.getRange(parsed.address);
    range.load(["rowIndex", "columnIndex", "rowCount", "columnCount"]);
    ranges.push({ sheetName: parsed.sheetName, range });
  }
  await context.sync();
  if (!isHighlightCurrent(runId)) return;

  for (const item of ranges) {
    totalCells += item.range.rowCount * item.range.columnCount;
    if (totalCells > MAX_HIGHLIGHT_CELLS) return;
  }

  const cells: Array<{ sheetName: string; address: string; cell: Excel.Range }> = [];
  for (const item of ranges) {
    for (let r = 0; r < item.range.rowCount; r += 1) {
      for (let c = 0; c < item.range.columnCount; c += 1) {
        const cell = item.range.getCell(r, c);
        cell.format.fill.load(["color", "pattern"]);
        cells.push({
          sheetName: item.sheetName,
          address: toA1(item.range.rowIndex + r, item.range.columnIndex + c),
          cell,
        });
      }
    }
  }
  await context.sync();
  if (!isHighlightCurrent(runId)) return;

  highlightedNodeFills = cells
    .filter((item) => !isRootLocation(`${item.sheetName}!${item.address}`))
    .map((item) => ({
      sheetName: item.sheetName,
      address: item.address,
      color: item.cell.format.fill.color ?? null,
      pattern: item.cell.format.fill.pattern ?? null,
    }));
  for (const item of cells) {
    if (isRootLocation(`${item.sheetName}!${item.address}`)) continue;
    item.cell.format.fill.pattern = "Solid";
    item.cell.format.fill.color = NODE_HIGHLIGHT_COLOR;
  }
}

function isHighlightCurrent(runId: number): boolean {
  return runId === highlightRunId && !isExplorerClosing && activeDialog !== null;
}

async function restoreFormulaExplorerRoot(): Promise<void> {
  const fill = originalRootFill;
  originalRootFill = null;
  rootAddress = null;
  if (!fill) return;
  await restoreFills([fill]);
}

async function restoreHighlightedNode(): Promise<void> {
  const fills = highlightedNodeFills;
  highlightedNodeFills = [];
  if (fills.length === 0) return;
  await restoreFills(fills);
}

async function restoreFills(fills: SavedFill[]): Promise<void> {
  try {
    await Excel.run(async (context) => {
      for (const fill of fills) {
        const cell = context.workbook.worksheets.getItem(fill.sheetName).getRange(fill.address);
        if (!fill.color) {
          cell.format.fill.clear();
        } else {
          cell.format.fill.pattern = (fill.pattern || "Solid") as Excel.FillPattern;
          cell.format.fill.color = fill.color;
        }
      }
      await context.sync();
    });
  } catch {
    // Best-effort visual cleanup.
  }
}

function schedulePullFocusToGrid(): void {
  setTimeout(() => {
    if (activeDialog !== null) return;
    void Excel.run(async (context) => {
      if (Office.context.requirements.isSetSupported("ExcelApiDesktop", "1.1")) {
        context.workbook.focus();
        await context.sync();
      }
    });
  }, 50);
}

async function expandReference(dialog: Office.Dialog, row: NodeRow): Promise<void> {
  try {
    if (!row.fullLocation) {
      sendAppendChildren(dialog, row.id, [], "No location to expand.");
      return;
    }
    const depth = row.dependencyDepth ?? 0;
    if (depth >= MAX_DEPENDENCY_DEPTH) {
      sendAppendChildren(dialog, row.id, [makeStatusRow(row, "<max depth>", "")], "Max depth reached.");
      return;
    }
    const snapshots = await readFormulaExplorerSnapshots([row]);
    const related = snapshots.get(row.id) ?? [];
    if (related.length > MAX_EXPANDED_RANGE_CELLS) {
      sendAppendChildren(
        dialog,
        row.id,
        [makeStatusRow(row, "<too large>", `${related.length}+ cells`)],
        "Range is too large."
      );
      return;
    }
    const { parentPatch, children } = await buildLazyChildren(row, related);
    sendAppendChildren(dialog, row.id, children, `${children.length} children`, parentPatch);
  } catch {
    sendAppendChildren(dialog, row.id, [makeStatusRow(row, "<expand failed>", "")], "Expand failed.");
  }
}

function sendAppendChildren(
  dialog: Office.Dialog,
  parentId: string,
  children: NodeRow[],
  message?: string,
  parentPatch?: Partial<NodeRow>
): void {
  if (activeDialog !== dialog) return;
  dialog.messageChild(JSON.stringify({ action: "appendChildren", parentId, children, message, parentPatch }));
}

async function buildLazyChildren(
  parent: NodeRow,
  snapshots: CellSnapshot[]
): Promise<{ parentPatch?: Partial<NodeRow>; children: NodeRow[] }> {
  const parentPath = parent.pathLocations ?? [];
  const ancestorPath = withoutCurrentLocation(parentPath, parent.fullLocation);
  const nextDepth = (parent.dependencyDepth ?? 0) + 1;
  if (snapshots.length !== 1) {
    return { children: snapshots.map((snapshot) => makeCellRow(parent, snapshot, ancestorPath, nextDepth)) };
  }

  const snapshot = snapshots[0];
  const parentPatch = makeExpandedParentPatch(parent, snapshot, ancestorPath, nextDepth);
  const normalized = normalizeLocation(snapshot.fullLocation);
  if (ancestorPath.includes(normalized)) {
    return { parentPatch, children: [makeCellRow(parent, snapshot, ancestorPath, nextDepth, "<circular>")] };
  }
  if (!snapshot.formula) {
    return { parentPatch, children: [] };
  }

  try {
    const parsed = parseFormula(snapshot.formula);
    const normalizedPath = buildChildPath(parentPath, normalized);
    const idPrefix = `${parent.id}>${normalized}`;
    const childRows = astToNodeRows({
      ast: parsed,
      formula: snapshot.formula,
      sourceSheet: snapshot.sheetName,
      sourceAddress: snapshot.address,
      rootValue: displaySnapshotValue(snapshot),
    })
      .slice(1)
      .map((child) => ({
        ...child,
        id: `${idPrefix}.${child.id}`,
        parentId: child.parentId === "root" ? parent.id : `${idPrefix}.${child.parentId}`,
        level: parent.level + child.level,
        dependencyDepth: nextDepth,
        pathLocations: normalizedPath,
        previewFormula: snapshot.formula,
        rootPreviewOnly: false,
      }));
    return { parentPatch, children: await materializeInlineRanges(await hydrateReferenceRows(childRows)) };
  } catch {
    return { parentPatch, children: [makeCellRow(parent, snapshot, parentPath, nextDepth, "<parse unavailable>")] };
  }
}

function makeExpandedParentPatch(
  parent: NodeRow,
  snapshot: CellSnapshot,
  parentPath: string[],
  dependencyDepth: number
): Partial<NodeRow> {
  const normalized = normalizeLocation(snapshot.fullLocation);
  const hasFormula = !!snapshot.formula && !parentPath.includes(normalized);
  return {
    element: renderCellElement(snapshot),
    label: snapshot.label,
    value: displaySnapshotValue(snapshot),
    location: truncateMiddle(snapshot.fullLocation, 18),
    fullLocation: snapshot.fullLocation,
    locations: [snapshot.fullLocation],
    start: 0,
    end: 0,
    previewFormula: snapshot.formula || undefined,
    previewText: snapshot.formula ? undefined : `${snapshot.fullLocation}: ${displaySnapshotValue(snapshot)}`,
    canExpandReference: false,
    dependencyDepth,
    pathLocations: hasFormula ? buildChildPath(parentPath, normalized) : parentPath,
    rootPreviewOnly: false,
  };
}

function makeCellRow(
  parent: NodeRow,
  snapshot: CellSnapshot,
  parentPath: string[],
  dependencyDepth: number,
  forcedValue?: string,
  forceHasChildren = false
): NodeRow {
  const normalized = normalizeLocation(snapshot.fullLocation);
  const circular = parentPath.includes(normalized);
  const hasFormula = !!snapshot.formula && !circular;
  const locations = [snapshot.fullLocation];
  return {
    id: `${parent.id}>${normalized}`,
    parentId: parent.id,
    level: parent.level + 1,
    element: renderCellElement(snapshot),
    label: snapshot.label,
    value: forcedValue ?? (circular ? "<circular>" : displaySnapshotValue(snapshot)),
    location: truncateMiddle(snapshot.fullLocation, 18),
    fullLocation: snapshot.fullLocation,
    locations,
    start: 0,
    end: snapshot.formula.length,
    hasChildren: forceHasChildren,
    previewFormula: snapshot.formula || undefined,
    previewText: snapshot.formula ? undefined : `${snapshot.fullLocation}: ${displaySnapshotValue(snapshot)}`,
    canExpandReference: hasFormula && !forceHasChildren && dependencyDepth < MAX_DEPENDENCY_DEPTH,
    dependencyDepth,
    pathLocations: hasFormula ? buildChildPath(parentPath, normalized) : parentPath,
  };
}

function makeStatusRow(parent: NodeRow, element: string, value: string): NodeRow {
  return {
    id: `${parent.id}>${element}`,
    parentId: parent.id,
    level: parent.level + 1,
    element,
    value,
    location: "",
    fullLocation: "",
    locations: [],
    start: 0,
    end: 0,
    hasChildren: false,
    previewFormula: parent.previewFormula,
    previewText: value || element,
    canExpandReference: false,
    dependencyDepth: parent.dependencyDepth,
    pathLocations: parent.pathLocations,
  };
}

async function materializeInlineRanges(rows: NodeRow[]): Promise<NodeRow[]> {
  const rangeRows = rows.filter((row) => row.canExpandReference && row.fullLocation.includes(":"));
  if (rangeRows.length === 0) return rows;

  const snapshotsByRow = await readFormulaExplorerSnapshots(rangeRows, INLINE_RANGE_CELL_LIMIT);
  const expanded = new Map<string, NodeRow[]>();
  for (const row of rangeRows) {
    const snapshots = snapshotsByRow.get(row.id) ?? [];
    if (snapshots.length === 0 || snapshots.length > INLINE_RANGE_CELL_LIMIT) continue;
    expanded.set(
      row.id,
      snapshots.map((snapshot) => makeInlineCellRow(row, snapshot))
    );
  }
  if (expanded.size === 0) return rows;

  const result: NodeRow[] = [];
  for (const row of rows) {
    const replacement = expanded.get(row.id);
    if (replacement) result.push(...replacement);
    else result.push(row);
  }
  return result;
}

async function hydrateReferenceRows(rows: NodeRow[]): Promise<NodeRow[]> {
  const candidates = rows.filter((row) => row.canExpandReference && row.fullLocation && !row.fullLocation.includes(":"));
  if (candidates.length === 0) return rows;

  const snapshotsByRow = await readFormulaExplorerSnapshots(candidates, 1);
  const patches = new Map<string, Partial<NodeRow>>();
  for (const row of candidates) {
    const snapshot = snapshotsByRow.get(row.id)?.[0];
    if (!snapshot) continue;
    const parentPath = row.pathLocations ?? [];
    const normalized = normalizeLocation(snapshot.fullLocation);
    const circular = parentPath.includes(normalized);
    patches.set(row.id, {
      value: circular ? "<circular>" : displaySnapshotValue(snapshot),
      element: renderCellElement(snapshot),
      label: snapshot.label,
      location: truncateMiddle(snapshot.fullLocation, 18),
      fullLocation: snapshot.fullLocation,
      locations: [snapshot.fullLocation],
      canExpandReference: !!snapshot.formula && !circular && (row.dependencyDepth ?? 0) < MAX_DEPENDENCY_DEPTH,
      pathLocations: !!snapshot.formula && !circular ? buildChildPath(parentPath, normalized) : parentPath,
    });
  }

  return rows.map((row) => ({ ...row, ...patches.get(row.id) }));
}

function makeInlineCellRow(rangeRow: NodeRow, snapshot: CellSnapshot): NodeRow {
  const normalized = normalizeLocation(snapshot.fullLocation);
  const parentPath = rangeRow.pathLocations ?? [];
  const hasFormula = !!snapshot.formula && !parentPath.includes(normalized);
  return {
    id: `${rangeRow.id}>${normalized}`,
    parentId: rangeRow.parentId,
    level: rangeRow.level,
    element: renderCellElement(snapshot),
    label: snapshot.label,
    value: displaySnapshotValue(snapshot),
    location: truncateMiddle(snapshot.fullLocation, 18),
    fullLocation: snapshot.fullLocation,
    locations: [snapshot.fullLocation],
    start: rangeRow.start,
    end: rangeRow.end,
    hasChildren: false,
    previewFormula: rangeRow.previewFormula,
    canExpandReference: hasFormula && (rangeRow.dependencyDepth ?? 0) < MAX_DEPENDENCY_DEPTH,
    dependencyDepth: rangeRow.dependencyDepth,
    pathLocations: hasFormula ? buildChildPath(parentPath, normalized) : parentPath,
    rootPreviewOnly: rangeRow.rootPreviewOnly,
  };
}

function renderCellElement(snapshot: CellSnapshot): string {
  const address = snapshot.label ? `${snapshot.address} (${snapshot.label})` : snapshot.address;
  const directReference = snapshot.formula.match(/^=\s*('(?:[^']|'')+'|[A-Za-z0-9_ .]+)?!?\$?[A-Z]{1,3}\$?\d{1,7}\s*$/);
  if (!directReference) return address;
  return `${address} = ${snapshot.formula.slice(1).trim()}`;
}

function buildChildPath(parentPath: string[], current: string): string[] {
  const path = parentPath.includes(current) ? [...parentPath] : [...parentPath, current];
  return path;
}

function withoutCurrentLocation(path: string[], currentLocation: string): string[] {
  if (!currentLocation) return path;
  const current = normalizeLocation(currentLocation);
  return path.filter((item) => normalizeLocation(item) !== current);
}

type CellSnapshot = {
  fullLocation: string;
  sheetName: string;
  address: string;
  formula: string;
  value: unknown;
  displayValue?: string;
  numberFormat?: string;
  label?: string;
};

async function readFormulaExplorerSnapshots(
  rows: NodeRow[],
  maxCells = MAX_EXPANDED_RANGE_CELLS
): Promise<Map<string, CellSnapshot[]>> {
  const result = new Map<string, CellSnapshot[]>();
  if (rows.length === 0) return result;
  await Excel.run(async (context) => {
    const parsedRows: Array<{ row: NodeRow; parsed: ParsedLocation }> = [];
    const sheetMap = new Map<string, Excel.Worksheet>();
    for (const row of rows) {
      const parsed = parseFormulaExplorerLocation(row.fullLocation);
      if (!parsed) continue;
      parsedRows.push({ row, parsed });
      if (!sheetMap.has(parsed.sheetName)) {
        const sheet = context.workbook.worksheets.getItemOrNullObject(parsed.sheetName);
        sheet.load("isNullObject");
        sheetMap.set(parsed.sheetName, sheet);
      }
    }
    await context.sync();

    const usedRanges = new Map<string, Excel.Range>();
    for (const [sheetName, sheet] of sheetMap) {
      if (sheet.isNullObject) continue;
      const usedRange = sheet.getUsedRangeOrNullObject();
      usedRange.load(["isNullObject", "columnIndex"]);
      usedRanges.set(sheetName, usedRange);
    }

    const queued: Array<{ row: NodeRow; range: Excel.Range; parsed: ParsedLocation }> = [];
    for (const item of parsedRows) {
      const sheet = sheetMap.get(item.parsed.sheetName);
      if (!sheet || sheet.isNullObject) continue;
      const range = sheet.getRange(item.parsed.address);
      range.load(["address", "rowIndex", "columnIndex", "rowCount", "columnCount"]);
      queued.push({ row: item.row, range, parsed: item.parsed });
    }
    await context.sync();

    const usedStartColumns = new Map<string, number>();
    for (const [sheetName, usedRange] of usedRanges) {
      usedStartColumns.set(sheetName, usedRange.isNullObject ? 0 : usedRange.columnIndex);
    }

    const loaded = queued.filter((item) => {
      const cellCount = item.range.rowCount * item.range.columnCount;
      if (cellCount > maxCells) {
        result.set(
          item.row.id,
          Array.from({ length: maxCells + 1 }, (_, index) => ({
            sheetName: item.parsed.sheetName,
            address: index === 0 ? item.parsed.address : "",
            fullLocation: `${item.parsed.sheetName}!${item.parsed.address}`,
            formula: "",
            value: "",
            displayValue: "",
          }))
        );
        return false;
      }
      item.range.load(["values", "formulas", "text", "numberFormat"]);
      return true;
    });
    const labelRequests = queueLabelRequests(loaded, usedStartColumns);
    await context.sync();
    const labels = resolveLabelRequests(labelRequests);

    for (const item of loaded) {
      const snapshots: CellSnapshot[] = [];
      for (let r = 0; r < item.range.rowCount; r += 1) {
        for (let c = 0; c < item.range.columnCount; c += 1) {
          const address = toA1(item.range.rowIndex + r, item.range.columnIndex + c);
          const labelKey = labelLookupKey(item.parsed.sheetName, item.range.rowIndex + r);
          snapshots.push({
            sheetName: item.parsed.sheetName,
            address,
            fullLocation: `${item.parsed.sheetName}!${address}`,
            formula: String(item.range.formulas?.[r]?.[c] ?? ""),
            value: item.range.values?.[r]?.[c],
            displayValue: formatWorkbookDisplayValue(item.range.text?.[r]?.[c], item.range.values?.[r]?.[c]),
            numberFormat: String(item.range.numberFormat?.[r]?.[c] ?? ""),
            label: labels.get(labelKey),
          });
        }
      }
      result.set(item.row.id, snapshots);
    }
  });
  return result;
}

type LoadedRangeSnapshotRequest = {
  row: NodeRow;
  range: Excel.Range;
  parsed: ParsedLocation;
};

type LabelLookupRequest = {
  key: string;
  range: Excel.Range;
};

function queueLabelRequests(
  items: LoadedRangeSnapshotRequest[],
  usedStartColumns: Map<string, number>
): LabelLookupRequest[] {
  const requests = new Map<string, LabelLookupRequest>();
  for (const item of items) {
    const sheet = item.range.worksheet;
    for (let r = 0; r < item.range.rowCount; r += 1) {
      const rowIndex = item.range.rowIndex + r;
      const window = computeLeftLabelLookupWindow({
        targetColumnIndex: item.range.columnIndex,
        usedStartColumnIndex: usedStartColumns.get(item.parsed.sheetName) ?? 0,
        maxColumns: LABEL_LOOKUP_LEFT_COLUMNS,
      });
      if (!window) continue;
      const key = labelLookupKey(item.parsed.sheetName, rowIndex);
      if (requests.has(key)) continue;
      const range = sheet.getRangeByIndexes(rowIndex, window.startColumnIndex, 1, window.columnCount);
      range.load(["text", "formulas"]);
      requests.set(key, { key, range });
    }
  }
  return [...requests.values()];
}

function resolveLabelRequests(requests: LabelLookupRequest[]): Map<string, string> {
  const labels = new Map<string, string>();
  for (const request of requests) {
    const text = request.range.text?.[0] ?? [];
    const formulas = request.range.formulas?.[0] ?? [];
    const label = pickNearestLeftLabel(
      text.map((cellText, index) => ({
        text: cellText,
        formula: formulas[index],
      }))
    );
    if (label) labels.set(request.key, label);
  }
  return labels;
}

function labelLookupKey(sheetName: string, rowIndex: number): string {
  return `${sheetName.toUpperCase()}!${rowIndex}`;
}

function displaySnapshotValue(snapshot: CellSnapshot): string {
  return formatWorkbookDisplayValue(snapshot.displayValue, snapshot.value);
}

type ParsedLocation = { sheetName: string; address: string };

function parseFormulaExplorerLocation(location: string): ParsedLocation | null {
  const bang = location.lastIndexOf("!");
  if (bang <= 0 || bang >= location.length - 1) return null;
  return {
    sheetName: location.slice(0, bang).replace(/^'|'$/g, "").replace(/''/g, "'"),
    address: location.slice(bang + 1),
  };
}

function isRootLocation(location: string): boolean {
  if (!rootAddress) return false;
  return normalizeLocation(location) === normalizeLocation(`${rootAddress.sheetName}!${rootAddress.address}`);
}

function normalizeLocation(location: string): string {
  const bang = location.lastIndexOf("!");
  if (bang < 0) return location.replace(/\$/g, "").toUpperCase();
  const sheet = location.slice(0, bang).replace(/^'|'$/g, "").replace(/''/g, "'").toUpperCase();
  const address = location.slice(bang + 1).replace(/\$/g, "").toUpperCase();
  return `${sheet}!${address}`;
}

function truncateMiddle(value: string, max: number): string {
  if (value.length <= max) return value;
  const left = Math.ceil((max - 3) / 2);
  const right = Math.floor((max - 3) / 2);
  return `${value.slice(0, left)}...${value.slice(value.length - right)}`;
}

function toA1(rowIndex: number, colIndex: number): string {
  let col = "";
  let n = colIndex + 1;
  while (n > 0) {
    const rem = (n - 1) % 26;
    col = String.fromCharCode(65 + rem) + col;
    n = Math.floor((n - rem - 1) / 26);
  }
  return `${col}${rowIndex + 1}`;
}
