import type { AstNode, NodeRow } from "./astTypes";

export type NodeValueMap = Record<string, string>;

const MAX_RANGE_EXPANSION_CELLS = 50;

export function astToNodeRows(input: {
  ast: AstNode;
  formula: string;
  sourceSheet: string;
  sourceAddress: string;
  sourceLabel?: string;
  rootValue: string;
  values?: NodeValueMap;
}): NodeRow[] {
  const rows: NodeRow[] = [];
  const values = input.values ?? {};

  const visit = (
    node: AstNode,
    id: string,
    parentId: string | null,
    level: number
  ): void => {
    const expanded = expandedChildrenOf(node);
    const locations = resolveLocations(node, input.sourceSheet, input.sourceAddress);
    const fullLocation = locations[0] ?? "";
    rows.push({
      id,
      parentId,
      level,
      element: renderElement(node, input.formula, input.sourceAddress, input.sourceLabel),
      label: node.kind === "root" ? input.sourceLabel : undefined,
      value: node.kind === "root" ? input.rootValue : values[id] ?? defaultValue(node),
      location: renderLocation(locations),
      fullLocation,
      locations,
      start: node.start,
      end: node.end,
      hasChildren: expanded.length > 0,
      previewFormula: input.formula,
      canExpandReference: node.kind === "cellRef" || node.kind === "rangeRef",
      dependencyDepth: 0,
      pathLocations: [normalizeLocation(`${input.sourceSheet}!${input.sourceAddress}`)],
    });

    expanded.forEach(({ child, idSuffix }) => {
      visit(child, `${id}.${idSuffix}`, id, level + 1);
    });
  };

  visit(input.ast, "root", null, 0);
  return rows;
}

export function renderSubExpression(formula: string, node: AstNode): string {
  return formula.slice(node.start, node.end);
}

export function getChildren(node: AstNode): AstNode[] {
  switch (node.kind) {
    case "root":
      return [node.child];
    case "functionCall":
      return node.args;
    case "binaryOp":
      return [node.left, node.right];
    case "unaryOp":
    case "percent":
      return [node.operand];
    case "parens":
      return [node.child];
    default:
      return [];
  }
}

/**
 * Return children with range refs auto-expanded into synthetic cell refs when
 * the parent is a function call and the range fits within the expansion cap.
 * Binary/unary operators keep their ranges opaque because they cannot host a
 * variable number of children without changing semantics.
 */
export function expandedChildrenOf(
  node: AstNode
): Array<{ child: AstNode; idSuffix: string }> {
  const raw = getChildren(node);
  if (node.kind === "binaryOp" && shouldFlattenOperator(node.op)) {
    return flattenBinaryChain(node, node.op).map((child, index) => ({
      child,
      idSuffix: String(index),
    }));
  }

  const result: Array<{ child: AstNode; idSuffix: string }> = [];
  raw.forEach((child, index) => {
    if (node.kind === "functionCall" && child.kind === "rangeRef") {
      const cells = expandRangeAddress(child.address);
      if (cells && cells.length > 0 && cells.length <= MAX_RANGE_EXPANSION_CELLS) {
        cells.forEach((cellAddress, cellIdx) => {
          const synthetic: AstNode = {
            kind: "cellRef",
            sheet: child.sheet,
            address: cellAddress,
            start: child.start,
            end: child.end,
          };
          result.push({ child: synthetic, idSuffix: `${index}.${cellIdx}` });
        });
        return;
      }
    }
    result.push({ child, idSuffix: String(index) });
  });
  return result;
}

function shouldFlattenOperator(op: string): boolean {
  return op === "+" || op === "*" || op === "&";
}

function flattenBinaryChain(node: AstNode, op: string): AstNode[] {
  if (node.kind !== "binaryOp" || node.op !== op) return [node];
  return [...flattenBinaryChain(node.left, op), ...flattenBinaryChain(node.right, op)];
}

export function nodeContainsMultiCellRange(node: AstNode): boolean {
  if (node.kind === "rangeRef") return true;
  return getChildren(node).some(nodeContainsMultiCellRange);
}

export function isAggregatorNode(node: AstNode): boolean {
  return (
    node.kind === "functionCall" &&
    ["SUM", "SUMIF", "SUMIFS", "SUMPRODUCT", "AVERAGE", "COUNT", "COUNTA", "MIN", "MAX"].includes(
      node.name.toUpperCase()
    )
  );
}

export function collectEvaluableNodes(ast: AstNode): Array<{ id: string; node: AstNode }> {
  const result: Array<{ id: string; node: AstNode }> = [];
  const visit = (node: AstNode, id: string): void => {
    if (shouldEvaluate(node)) result.push({ id, node });
    expandedChildrenOf(node).forEach(({ child, idSuffix }) =>
      visit(child, `${id}.${idSuffix}`)
    );
  };
  visit(ast, "root");
  return result;
}

function shouldEvaluate(node: AstNode): boolean {
  if (node.kind === "root") return false;
  if (node.kind === "cellRef") return true;
  if (["functionCall", "binaryOp", "unaryOp", "percent", "parens"].includes(node.kind)) {
    if (nodeContainsMultiCellRange(node) && !isAggregatorNode(node)) return false;
    return true;
  }
  return false;
}

function renderElement(node: AstNode, formula: string, sourceAddress: string, sourceLabel?: string): string {
  switch (node.kind) {
    case "root":
      return sourceLabel ? `${sourceAddress} (${sourceLabel})` : sourceAddress;
    case "cellRef":
    case "rangeRef":
      return node.address;
    case "namedRange":
      return node.name;
    case "number":
      return String(node.value);
    case "string":
      return `"${node.value}"`;
    case "boolean":
      return node.value ? "TRUE" : "FALSE";
    case "error":
      return node.value;
    default:
      return renderSubExpression(formula, node);
  }
}

function defaultValue(node: AstNode): string {
  switch (node.kind) {
    case "number":
      return formatDisplayValue(node.value);
    case "string":
      return `"${node.value}"`;
    case "boolean":
      return node.value ? "TRUE" : "FALSE";
    case "error":
      return node.value;
    case "rangeRef":
      return "<array>";
    case "unknown":
      return "<formula>";
    default:
      return "";
  }
}

function resolveLocations(node: AstNode, sourceSheet: string, sourceAddress: string): string[] {
  if (node.kind === "root") return [`${sourceSheet}!${sourceAddress}`];
  if (node.kind === "cellRef" || node.kind === "rangeRef") {
    return [`${node.sheet ?? sourceSheet}!${node.address}`];
  }
  return collectReferencedLocations(node, sourceSheet);
}

function collectReferencedLocations(node: AstNode, sourceSheet: string): string[] {
  const locations: string[] = [];
  const seen = new Set<string>();

  const add = (location: string): void => {
    const normalized = normalizeLocation(location);
    if (seen.has(normalized)) return;
    seen.add(normalized);
    locations.push(location);
  };

  const visit = (current: AstNode): void => {
    if (current.kind === "cellRef" || current.kind === "rangeRef") {
      add(`${current.sheet ?? sourceSheet}!${current.address}`);
      return;
    }
    getChildren(current).forEach(visit);
  };

  visit(node);
  return locations;
}

function renderLocation(locations: string[]): string {
  if (locations.length === 0) return "";
  if (locations.length === 1) return truncateMiddle(locations[0], 18);
  return `${locations.length} refs`;
}

export function formatDisplayValue(value: unknown): string {
  if (value === null || value === undefined) return "";
  if (typeof value === "number") {
    return new Intl.NumberFormat("en-US", { maximumFractionDigits: 6 }).format(value);
  }
  if (typeof value === "boolean") return value ? "TRUE" : "FALSE";
  return String(value);
}

export function formatWorkbookDisplayValue(displayText: unknown, value: unknown): string {
  if (typeof displayText === "string" && displayText.length > 0) return displayText;
  return formatDisplayValue(value);
}

export type LabelCandidate = {
  text: unknown;
  formula?: unknown;
};

export type LeftLabelLookupWindow = {
  startColumnIndex: number;
  columnCount: number;
};

export function pickNearestLeftLabel(candidatesFromLeftToRight: LabelCandidate[]): string {
  for (let index = candidatesFromLeftToRight.length - 1; index >= 0; index -= 1) {
    const candidate = candidatesFromLeftToRight[index];
    const text = normalizeLabelText(candidate.text);
    if (!text) continue;
    if (hasFormula(candidate.formula)) continue;
    if (isNumericOnlyLabel(text)) continue;
    if (isPeriodLabel(text)) continue;
    return text;
  }
  return "";
}

export function computeLeftLabelLookupWindow(input: {
  targetColumnIndex: number;
  usedStartColumnIndex: number;
  maxColumns: number;
}): LeftLabelLookupWindow | null {
  const targetColumnIndex = Math.max(0, Math.floor(input.targetColumnIndex));
  const usedStartColumnIndex = Math.max(0, Math.floor(input.usedStartColumnIndex));
  const maxColumns = Math.max(0, Math.floor(input.maxColumns));
  if (targetColumnIndex <= 0 || maxColumns <= 0) return null;
  const startColumnIndex = Math.max(usedStartColumnIndex, targetColumnIndex - maxColumns);
  const columnCount = targetColumnIndex - startColumnIndex;
  if (columnCount <= 0) return null;
  return { startColumnIndex, columnCount };
}

function normalizeLabelText(value: unknown): string {
  if (typeof value !== "string") return "";
  return value.replace(/\s+/g, " ").trim();
}

function hasFormula(value: unknown): boolean {
  return typeof value === "string" && value.trim().startsWith("=");
}

function isNumericOnlyLabel(value: string): boolean {
  const normalized = value.replace(/[$,()\s]/g, "");
  return normalized !== "" && /^-?\d+(?:\.\d+)?%?$/.test(normalized);
}

function isPeriodLabel(value: string): boolean {
  const normalized = value.trim().toUpperCase();
  return (
    normalized === "%" ||
    /^(?:FY|FYE|CY|YEAR)?\s*20\d{2}$/.test(normalized) ||
    /^20\d{2}\s*(?:A|E|F|ACTUAL|FORECAST|BUDGET)?$/.test(normalized)
  );
}

function truncateMiddle(value: string, max: number): string {
  if (value.length <= max) return value;
  const left = Math.ceil((max - 1) / 2);
  const right = Math.floor((max - 1) / 2);
  return `${value.slice(0, left)}...${value.slice(value.length - right)}`;
}

function normalizeLocation(location: string): string {
  const bang = location.lastIndexOf("!");
  if (bang < 0) return location.replace(/\$/g, "").toUpperCase();
  const sheet = location.slice(0, bang).replace(/^'|'$/g, "").replace(/''/g, "'").toUpperCase();
  const address = location.slice(bang + 1).replace(/\$/g, "").toUpperCase();
  return `${sheet}!${address}`;
}

/**
 * Reconstruct a formula from an AST subtree, prefixing every unqualified
 * cell/range reference with the source sheet. Replaces the prior regex-based
 * qualifier which double-prefixed already-qualified refs like `Sheet1!A1`.
 */
export function qualifyAstToFormula(node: AstNode, sourceSheet: string): string {
  const escapedSheet = sourceSheet.replace(/'/g, "''");
  const defaultQuoted = `'${escapedSheet}'!`;

  const rebuild = (n: AstNode): string => {
    switch (n.kind) {
      case "root":
        return rebuild(n.child);
      case "number":
        return String(n.value);
      case "string":
        return `"${n.value.replace(/"/g, '""')}"`;
      case "boolean":
        return n.value ? "TRUE" : "FALSE";
      case "error":
        return n.value;
      case "cellRef":
      case "rangeRef": {
        if (n.sheet) {
          const sheetEsc = n.sheet.replace(/'/g, "''");
          return `'${sheetEsc}'!${n.address}`;
        }
        return `${defaultQuoted}${n.address}`;
      }
      case "namedRange":
        return n.name;
      case "functionCall":
        return `${n.name}(${n.args.map(rebuild).join(",")})`;
      case "binaryOp":
        return `(${rebuild(n.left)}${n.op}${rebuild(n.right)})`;
      case "unaryOp":
        return `${n.op}${rebuild(n.operand)}`;
      case "percent":
        return `${rebuild(n.operand)}%`;
      case "parens":
        return `(${rebuild(n.child)})`;
      case "unknown":
        return n.text;
    }
  };

  return rebuild(node);
}

function expandRangeAddress(address: string): string[] | null {
  const match = address.match(/^\$?([A-Z]+)\$?(\d+):\$?([A-Z]+)\$?(\d+)$/i);
  if (!match) return null;
  const col1 = columnToNumber(match[1]);
  const col2 = columnToNumber(match[3]);
  const row1 = Number(match[2]);
  const row2 = Number(match[4]);
  if (!Number.isFinite(row1) || !Number.isFinite(row2)) return null;
  const minCol = Math.min(col1, col2);
  const maxCol = Math.max(col1, col2);
  const minRow = Math.min(row1, row2);
  const maxRow = Math.max(row1, row2);
  const total = (maxCol - minCol + 1) * (maxRow - minRow + 1);
  if (total <= 0 || total > MAX_RANGE_EXPANSION_CELLS) return null;
  const cells: string[] = [];
  for (let r = minRow; r <= maxRow; r += 1) {
    for (let c = minCol; c <= maxCol; c += 1) {
      cells.push(`${numberToColumn(c)}${r}`);
    }
  }
  return cells;
}

function columnToNumber(col: string): number {
  let n = 0;
  for (const ch of col.toUpperCase()) {
    n = n * 26 + (ch.charCodeAt(0) - 64);
  }
  return n;
}

function numberToColumn(n: number): string {
  let result = "";
  let x = n;
  while (x > 0) {
    const rem = (x - 1) % 26;
    result = String.fromCharCode(65 + rem) + result;
    x = Math.floor((x - 1) / 26);
  }
  return result;
}
