export type DataFlowSheet = {
  name: string;
  hidden: boolean;
};

export type DataFlowCell = {
  address: string;
  formula: string;
};

export type DataFlowEdge = {
  fromSheet: string;
  toSheet: string;
  count: number;
  formulaCells: DataFlowCell[];
};

export type DataFlowModel = {
  sheets: DataFlowSheet[];
  edges: DataFlowEdge[];
};

export type DataFlowSheetSnapshot = DataFlowSheet & {
  formulas: string[][];
  startRow: number;
  startColumn: number;
};

export function buildDataFlowModel(sheets: DataFlowSheetSnapshot[]): DataFlowModel {
  const sheetLookup = new Map(sheets.map((sheet) => [normalizeSheetName(sheet.name), sheet.name]));
  const edges = new Map<string, DataFlowEdge>();

  for (const sheet of sheets) {
    for (let r = 0; r < sheet.formulas.length; r += 1) {
      const row = sheet.formulas[r] ?? [];
      for (let c = 0; c < row.length; c += 1) {
        const formula = String(row[c] ?? "");
        if (!formula.startsWith("=")) continue;
        const targetSheets = referencedSheets(formula, sheet.name, sheetLookup);
        if (targetSheets.size === 0) continue;
        const cell = { address: a1(sheet.startRow + r, sheet.startColumn + c), formula };
        for (const toSheet of targetSheets) {
          const key = `${normalizeSheetName(sheet.name)}\u0000${normalizeSheetName(toSheet)}`;
          const edge =
            edges.get(key) ??
            {
              fromSheet: sheet.name,
              toSheet,
              count: 0,
              formulaCells: [],
            };
          edge.count += 1;
          edge.formulaCells.push(cell);
          edges.set(key, edge);
        }
      }
    }
  }

  return {
    sheets: sheets.map(({ name, hidden }) => ({ name, hidden })),
    edges: [...edges.values()],
  };
}

function referencedSheets(
  formula: string,
  sourceSheet: string,
  sheetLookup: Map<string, string>
): Set<string> {
  const result = new Set<string>();

  for (const sheet of quotedSheetRefs(formula)) {
    const resolved = sheetLookup.get(normalizeSheetName(sheet));
    if (resolved) result.add(resolved);
  }
  for (const sheet of bareSheetRefs(formula)) {
    const resolved = sheetLookup.get(normalizeSheetName(sheet));
    if (resolved) result.add(resolved);
  }
  if (hasLocalCellRef(formula)) result.add(sourceSheet);
  return result;
}

function quotedSheetRefs(formula: string): string[] {
  return [...formula.matchAll(/'((?:[^']|'')+)'!\$?[A-Z]{1,3}\$?\d{1,7}(?::\$?[A-Z]{1,3}\$?\d{1,7})?/gi)].map(
    (match) => match[1].replace(/''/g, "'")
  );
}

function bareSheetRefs(formula: string): string[] {
  return [
    ...formula.matchAll(
      /(?:^|[^A-Za-z0-9_.'\]])([A-Za-z_][A-Za-z0-9_.]*)!\$?[A-Z]{1,3}\$?\d{1,7}(?::\$?[A-Z]{1,3}\$?\d{1,7})?/gi
    ),
  ].map((match) => match[1]);
}

function hasLocalCellRef(formula: string): boolean {
  const withoutSheetRefs = formula
    .replace(/'((?:[^']|'')+)'!\$?[A-Z]{1,3}\$?\d{1,7}(?::\$?[A-Z]{1,3}\$?\d{1,7})?/gi, "")
    .replace(
      /(?:^|[^A-Za-z0-9_.'\]])([A-Za-z_][A-Za-z0-9_.]*)!\$?[A-Z]{1,3}\$?\d{1,7}(?::\$?[A-Z]{1,3}\$?\d{1,7})?/gi,
      ""
    );
  return /(?:^|[^A-Za-z0-9_.])\$?[A-Z]{1,3}\$?\d{1,7}(?::\$?[A-Z]{1,3}\$?\d{1,7})?/i.test(withoutSheetRefs);
}

function normalizeSheetName(name: string): string {
  return name.replace(/^'|'$/g, "").replace(/''/g, "'").toUpperCase();
}

function a1(rowIndex: number, colIndex: number): string {
  let col = "";
  let n = colIndex + 1;
  while (n > 0) {
    const rem = (n - 1) % 26;
    col = String.fromCharCode(65 + rem) + col;
    n = Math.floor((n - rem - 1) / 26);
  }
  return `${col}${rowIndex + 1}`;
}
